package main

// Compliant: Unique, properly ordered conditions
func processUser(user *User) string {
    // GOOD: Each condition is unique and reachable
    if user.Age >= 18 && user.IsActive {
        return "adult_active"
    } else if user.Age >= 18 && !user.IsActive {
        return "adult_inactive"
    } else if user.Age < 18 {
        return "minor"
    } else {
        return "unknown"
    }
}

// Alternative approach using early returns
func processUserEarlyReturn(user *User) string {
    // GOOD: Clear, non-overlapping logic
    if user.Age < 18 {
        return "minor"
    }

    if user.IsActive {
        return "adult_active"
    }

    return "adult_inactive"
}

func calculateFee(amount float64, userType string) float64 {
    // GOOD: Conditions ordered from most specific to least specific
    if amount > 1000 && userType == "premium" {
        return amount * 0.01
    } else if amount > 1000 && userType == "standard" {
        return amount * 0.015
    } else if amount > 500 {
        return amount * 0.02
    } else {
        return amount * 0.03
    }
}

// Alternative approach with switch for cleaner logic
func calculateFeeSwitch(amount float64, userType string) float64 {
    // GOOD: Use switch to avoid complex conditions
    switch {
    case amount > 1000 && userType == "premium":
        return amount * 0.01
    case amount > 1000:
        return amount * 0.015
    case amount > 500:
        return amount * 0.02
    default:
        return amount * 0.03
    }
}
